#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_N 100005

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return x[1] - y[1];
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int intervals[N][2];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &intervals[i][0], &intervals[i][1]);
        }
        qsort(intervals, N, sizeof(intervals[0]), compare);
        int min_bombs = 0;
        int last_bomb = -1;
        for (int i = 0; i < N; i++) {
            if (intervals[i][0] > last_bomb) {
                min_bombs++;
                last_bomb = intervals[i][1];
            }
        }
        printf("%d\n", min_bombs);
    }
    return 0;
}

